#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int A, B, C, N;
        scanf("%d %d %d %d", &A, &B, &C, &N);
        long long X = 0, Y = 0;
        for (int x = 0; x <= N; x++) {
            for (int y = 0; y <= N; y++) {
                if (x * y == (x | y) * (x & y) + A * x + B * y + C) {
                    X += x;
                    Y += y;
                }
            }
        }
        printf("%lld %lld\n", X, Y);
    }
    return 0;
}

